module decision_tree_inference(  
    input [4:0] inputs,  // 5 binary input inputs  
    output reg decision     // 1-bit output decision  
);  
    always @(*) begin  
        if (inputs[0] == 1) begin  
            decision = 1;  
        end else if (inputs[1] == 1 && inputs[2] == 0) begin  
            decision = 0;  
        end else if (inputs[1] == 0 && inputs[3] == 1) begin  
            decision = 1;  
        end else if (inputs[1] == 0 && inputs[3] == 0) begin  
            decision = inputs[4];  
        end else begin  
            decision = 0;  // default case  
        end  
    end  
endmodule
